import{_ as s,o as a,c as e,aw as n}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"Use GCP KMS Signer","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Use GCP KMS Signer | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/operations/gcp-kms-signer.md","filePath":"guides/operations/gcp-kms-signer.md","lastUpdated":1774455097000}');const l=s({name:"guides/operations/gcp-kms-signer.md"},[["render",function(s,o,l,p,t,c){return a(),e("div",null,[...o[0]||(o[0]=[n('<h1 id="use-gcp-kms-signer" tabindex="-1">Use GCP KMS Signer <a class="header-anchor" href="#use-gcp-kms-signer" aria-label="Permalink to &quot;Use GCP KMS Signer&quot;">​</a></h1><p>Use this guide to run <code>ev-node</code> with a Google Cloud KMS-backed signer (<code>signer_type: kms</code>, <code>kms.provider: gcp</code>) instead of a local key file.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>A Google Cloud KMS asymmetric key version with: <ul><li><code>purpose: ASYMMETRIC_SIGN</code></li><li><code>algorithm: EC_SIGN_ED25519</code></li></ul></li><li>IAM permissions for runtime: <ul><li><code>cloudkms.cryptoKeyVersions.useToSign</code></li><li><code>cloudkms.cryptoKeyVersions.viewPublicKey</code></li></ul></li><li>Google credentials available to the node process: <ul><li>Application Default Credentials (recommended), or</li><li>service-account JSON file.</li></ul></li></ul><h2 id="_1-create-an-ed25519-kms-key-example" tabindex="-1">1. Create an ED25519 KMS key (example) <a class="header-anchor" href="#_1-create-an-ed25519-kms-key-example" aria-label="Permalink to &quot;1. Create an ED25519 KMS key (example)&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">gcloud</span><span style="color:#BFF3C2;"> kms</span><span style="color:#BFF3C2;"> keyrings</span><span style="color:#BFF3C2;"> create</span><span style="color:#BFF3C2;"> ev-node</span><span style="color:#FFECB6;"> --location=global</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">gcloud</span><span style="color:#BFF3C2;"> kms</span><span style="color:#BFF3C2;"> keys</span><span style="color:#BFF3C2;"> create</span><span style="color:#BFF3C2;"> signer</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --location=global</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --keyring=ev-node</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --purpose=asymmetric-signing</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --default-algorithm=ec-sign-ed25519</span></span></code></pre></div><p>Get key version resource name:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">gcloud</span><span style="color:#BFF3C2;"> kms</span><span style="color:#BFF3C2;"> keys</span><span style="color:#BFF3C2;"> versions</span><span style="color:#BFF3C2;"> list</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --location=global</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --keyring=ev-node</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --key=signer</span></span></code></pre></div><p>Use a full key version name like: <code>projects/&lt;project&gt;/locations/global/keyRings/ev-node/cryptoKeys/signer/cryptoKeyVersions/1</code></p><p>Create and export credentials for a service account:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># create</span></span>\n<span class="line"><span style="color:#94EEFF;">gcloud</span><span style="color:#BFF3C2;"> iam</span><span style="color:#BFF3C2;"> service-accounts</span><span style="color:#BFF3C2;"> create</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">kms-go-client</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --display-name</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">KMS Go Client Account</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># set permissions</span></span>\n<span class="line"><span style="color:#94EEFF;">gcloud</span><span style="color:#BFF3C2;"> projects</span><span style="color:#BFF3C2;"> add-iam-policy-binding</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">projec</span><span style="color:#DBD7CA;">t</span><span style="color:#888888;">&gt;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --member</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">serviceAccount:kms-go-client@&lt;project&gt;.iam.gserviceaccount.com</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --role</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">roles/cloudkms.publicKeyViewer</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --role</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">roles/cloudkms.signerVerifier</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"># export credentials file</span></span>\n<span class="line"><span style="color:#94EEFF;">gcloud</span><span style="color:#BFF3C2;"> iam</span><span style="color:#BFF3C2;"> service-accounts</span><span style="color:#BFF3C2;"> keys</span><span style="color:#BFF3C2;"> create</span><span style="color:#BFF3C2;"> /path/to/service-account.json</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">    --iam-account</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">kms-go-client@&lt;project&gt;.iam.gserviceaccount.com</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><h2 id="_2-configure-evnode-yaml" tabindex="-1">2. Configure <code>evnode.yaml</code> <a class="header-anchor" href="#_2-configure-evnode-yaml" aria-label="Permalink to &quot;2. Configure `evnode.yaml`&quot;">​</a></h2><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">signer</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  signer_type</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">kms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  kms</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">    provider</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">gcp</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">    gcp</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">      key_name</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">projects/my-project/locations/global/keyRings/ev-node/cryptoKeys/signer/cryptoKeyVersions/1</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">      credentials_file</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">/path/to/service-account.json</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#A0A0A0;"> # optional; ADC is used when omitted</span></span>\n<span class="line"><span style="color:#94EEFF;">      timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">1s</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#A0A0A0;">                                     # must be &gt; 0</span></span>\n<span class="line"><span style="color:#94EEFF;">      max_retries</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 3</span><span style="color:#A0A0A0;">                                    # must be &gt;= 0</span></span></code></pre></div><h2 id="_3-start-as-an-aggregator" tabindex="-1">3. Start as an aggregator <a class="header-anchor" href="#_3-start-as-an-aggregator" aria-label="Permalink to &quot;3. Start as an aggregator&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">evnode</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> --evnode.node.aggregator</span></span></code></pre></div><p>You should see a startup log line:</p><p><code>initialized GCP KMS signer via factory</code></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li><code>evnode.signer.kms.gcp.key_name is required when signer.signer_type is kms and signer.kms.provider is gcp</code>: Set <code>signer.kms.gcp.key_name</code>.</li><li><code>unsupported key type from KMS: expected ed25519</code>: Recreate key with <code>EC_SIGN_ED25519</code>.</li><li><code>KMS Sign failed ...</code>: Check IAM permissions, credentials, and network access to Cloud KMS.</li></ul>',19)])])}]]);export{o as __pageData,l as default};
